using System.Collections.Generic;
using UnityEngine;

public enum TimeOfDay
{
    Manha,
    Tarde,
    Noite,
    Madrugada
}

public enum WeatherType
{
    Limpo,
    Chuva,
    Neve,
    Tempestade,
    Neblina,
    VentoForte
}

/// <summary>
/// "Banco de dados" do estado do mundo: hora do dia, clima, mundo/área actual
/// e população das vilas. As condições de eventos de NPC (Etapa 1) leem este
/// estado através de WorldState.Instance.
///
/// A hora do dia é actualizada pelo DayNightCycle2D, o clima por um futuro
/// WeatherController, e o mundo/área actual por triggers como CameraAreaBounds.
/// </summary>
public class WorldState : MonoBehaviour
{
    public static WorldState Instance { get; private set; }

    [Header("Tempo")]
    [SerializeField] private TimeOfDay timeOfDay = TimeOfDay.Manha;

    [Header("Clima")]
    [SerializeField] private WeatherType weather = WeatherType.Limpo;

    [Header("Clima/Hora Manual (Etapa 8)")]
    [Tooltip("Enquanto activo, SetTimeOfDay (chamado todos os frames pelo DayNightCycle2D) é ignorado — a hora fica fixa no valor definido manualmente. Ao desactivar, a hora real volta a ser aplicada no frame seguinte.")]
    [SerializeField] private bool manualTimeActive;
    [SerializeField] private TimeOfDay manualTimeSaved;

    [Tooltip("Enquanto activo, SetWeather é ignorado — o clima fica fixo no valor definido manualmente. Ao desactivar, o clima de antes de activar é restaurado.")]
    [SerializeField] private bool manualWeatherActive;
    [SerializeField] private WeatherType manualWeatherSaved;

    [Header("Localização Actual")]
    [SerializeField] private WorldData currentWorld;
    [SerializeField] private AreaData currentArea;

    [Header("População das Vilas")]
    [SerializeField] private List<VillagePopulation> villagePopulations = new List<VillagePopulation>();

    public TimeOfDay CurrentTimeOfDay => timeOfDay;
    public WeatherType CurrentWeather => weather;
    public WorldData CurrentWorld => currentWorld;
    public AreaData CurrentArea => currentArea;

    public bool ManualTimeActive => manualTimeActive;
    public bool ManualWeatherActive => manualWeatherActive;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons"). Sem isto, um
    /// WorldState configurado numa cena (currentWorld/currentArea/clima
    /// iniciais) seria destruído ao encontrar a versão vazia auto-criada como
    /// Instance.
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        // Tarefa #22 (Menu Inicial — "Novo Jogo"): ver PlayerProgress.cs para a
        // explicação completa do mecanismo de fotografia/restauro.
        _initialSnapshotJson = JsonUtility.ToJson(this);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(WorldState) + " (Fallback)");
        var instance = go.AddComponent<WorldState>();
        instance.isAutoFallback = true;
    }

    // ---------------- Novo Jogo (Tarefa #22) ----------------

    private string _initialSnapshotJson;

    /// <summary>Repõe hora/clima/área/população das vilas para os valores configurados no Inspector no arranque — ver PlayerProgress.ResetForNewGame.</summary>
    public void ResetForNewGame()
    {
        if (!string.IsNullOrEmpty(_initialSnapshotJson))
            JsonUtility.FromJsonOverwrite(_initialSnapshotJson, this);

        CurrentAreaChanged?.Invoke(currentArea);
    }

    // ---------------- Tempo / Clima ----------------

    /// <summary>Chamado todos os frames pelo DayNightCycle2D. Ignorado enquanto a hora manual estiver activa.</summary>
    public void SetTimeOfDay(TimeOfDay value)
    {
        if (manualTimeActive) return;
        timeOfDay = value;
    }

    public bool IsTimeOfDay(TimeOfDay value) => timeOfDay == value;

    /// <summary>Ignorado enquanto o clima manual estiver activo.</summary>
    public void SetWeather(WeatherType value)
    {
        if (manualWeatherActive) return;
        weather = value;
    }

    public bool IsWeather(WeatherType value) => weather == value;

    // ---------------- Clima/Hora Manual (Etapa 8) ----------------

    /// <summary>
    /// Activa a hora manual com "value" (guardando a hora actual para restaurar
    /// depois, se ainda não estiver activa) — o DayNightCycle2D deixa de a alterar.
    /// Usado por Action_SetManualTimeOfDay.
    /// </summary>
    public void SetManualTimeOfDay(TimeOfDay value)
    {
        if (!manualTimeActive)
        {
            manualTimeSaved = timeOfDay;
            manualTimeActive = true;
        }

        timeOfDay = value;
    }

    /// <summary>
    /// Desactiva a hora manual. A hora real (calculada pelo DayNightCycle2D) volta
    /// a ser aplicada no frame seguinte; entretanto, restaura a hora guardada antes
    /// de activar o modo manual. Usado por Action_DisableManualTimeOfDay.
    /// </summary>
    public void DisableManualTimeOfDay()
    {
        if (!manualTimeActive) return;

        manualTimeActive = false;
        timeOfDay = manualTimeSaved;
    }

    /// <summary>
    /// Activa o clima manual com "value" (guardando o clima actual para restaurar
    /// depois, se ainda não estiver activo). Usado por Action_SetManualWeather.
    /// </summary>
    public void SetManualWeather(WeatherType value)
    {
        if (!manualWeatherActive)
        {
            manualWeatherSaved = weather;
            manualWeatherActive = true;
        }

        weather = value;
    }

    /// <summary>Desactiva o clima manual e restaura o clima de antes de o activar. Usado por Action_DisableManualWeather.</summary>
    public void DisableManualWeather()
    {
        if (!manualWeatherActive) return;

        manualWeatherActive = false;
        weather = manualWeatherSaved;
    }

    // ---------------- Mundo / Área ----------------

    /// <summary>
    /// Define a área actual. Devolve true se a área mudou de facto (usado por
    /// CameraAreaBounds para disparar o autosave apenas em mudanças reais de
    /// área/cidade, não em cada OnTriggerStay2D).
    /// </summary>
    /// <summary>Disparado quando a área actual muda (via SetCurrentArea) — HUD (banner de nome de área) e outros sistemas podem ligar-se aqui.</summary>
    public event System.Action<AreaData> CurrentAreaChanged;

    public bool SetCurrentArea(AreaData area)
    {
        if (area == null || currentArea == area) return false;

        currentArea = area;
        if (area.world != null) currentWorld = area.world;
        CurrentAreaChanged?.Invoke(currentArea);
        return true;
    }

    public void SetCurrentWorld(WorldData world) => currentWorld = world;

    public bool IsCurrentWorld(WorldData world) => world != null && currentWorld == world;
    public bool IsCurrentArea(AreaData area) => area != null && currentArea == area;

    // ---------------- População das Vilas ----------------

    /// <summary>
    /// Disparado sempre que a população de uma vila muda (via SetVillagePopulation ou
    /// AddVillagePopulation). Parâmetros: (villageId, current, max).
    ///
    /// Subscreve aqui para reagir automaticamente a mudanças de população:
    ///   • Música da vila: mudar o clip/versão do BGM conforme o nível.
    ///   • Lojas: activar/desactivar NPCs lojistas conforme a população.
    ///   • Decoração: activar GameObjects de ambiente (tendas, lanternas, etc.).
    ///   • Nível de evolução: calcular com GetVillagePopulationLevel(villageId, numLevels).
    /// </summary>
    public static event System.Action<string, int, int> VillagePopulationChanged;

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => VillagePopulationChanged = null;

    public VillagePopulation GetVillagePopulation(string villageId)
    {
        for (int i = 0; i < villagePopulations.Count; i++)
            if (villagePopulations[i].villageId == villageId) return villagePopulations[i];

        return null;
    }

    private VillagePopulation GetOrCreateVillagePopulation(string villageId)
    {
        var pop = GetVillagePopulation(villageId);
        if (pop != null) return pop;

        pop = new VillagePopulation { villageId = villageId };
        villagePopulations.Add(pop);
        return pop;
    }

    /// <summary>
    /// Define directamente "current" e "max" da população de uma vila (override
    /// manual — Action_SetVillagePopulation). Reseta rescuedCount e
    /// additionalPopulation para zero, tratando "current" como o total combinado.
    /// Usar apenas para overrides de design (cutscenes, reduções, forçar valor).
    /// Para sincronizar a partir dos resgates registados, usar
    /// <see cref="SyncRescuedPopulation"/>.
    /// </summary>
    public void SetVillagePopulation(string villageId, int current, int max)
    {
        var pop = GetOrCreateVillagePopulation(villageId);
        pop.current = current;
        pop.rescuedCount = current;
        pop.additionalPopulation = 0;
        pop.max = max;
        VillagePopulationChanged?.Invoke(villageId, pop.current, pop.max);
    }

    /// <summary>
    /// Actualiza o número de NPCs resgatados para esta vila (fonte:
    /// PlayerProgress.SyncVillagePopulationForWorld). Preserva
    /// additionalPopulation — ao contrário de SetVillagePopulation, não apaga
    /// a população extra (lojistas, visitantes). "current" = rescued + additional.
    /// </summary>
    internal void SyncRescuedPopulation(string villageId, int rescued, int max)
    {
        var pop = GetOrCreateVillagePopulation(villageId);
        pop.rescuedCount = rescued;
        pop.max = max;
        pop.current = rescued + pop.additionalPopulation;
        VillagePopulationChanged?.Invoke(villageId, pop.current, pop.max);
    }

    /// <summary>
    /// Adiciona 1 NPC adicional (lojista, visitante, NPC de evento) à vila,
    /// sem passar por PlayerProgress.AddNpcRescued. Não conta para a percentagem
    /// de restauração — apenas para a contagem visual. Preservado durante
    /// SyncAllVillagePopulations (não é sobrescrito pelo sistema de resgates).
    /// </summary>
    public void AddVillagePopulation(string villageId)
    {
        var pop = GetOrCreateVillagePopulation(villageId);

        // Respeita o máximo total (rescued + additional <= max, se max > 0).
        if (pop.max <= 0 || pop.current < pop.max)
        {
            pop.additionalPopulation++;
            pop.current = pop.rescuedCount + pop.additionalPopulation;
        }

        VillagePopulationChanged?.Invoke(villageId, pop.current, pop.max);
    }

    /// <summary>
    /// Devolve o nível de evolução da vila (0 a numLevels-1) baseado na razão
    /// rescuedCount/max (apenas NPCs resgatados — exclui população adicional).
    /// Útil para indexar um array de música, lojas ou decorações.
    ///
    /// Exemplo: GetVillagePopulationLevel("VilaMundo1", 4)
    ///   → 0..3 consoante 0–24%, 25–49%, 50–74%, 75–100% de NPCs resgatados.
    /// </summary>
    public int GetVillagePopulationLevel(string villageId, int numLevels = 4)
    {
        if (numLevels <= 1) return 0;
        var pop = GetVillagePopulation(villageId);
        if (pop == null || pop.max <= 0) return 0;

        float ratio = Mathf.Clamp01((float)pop.rescuedCount / pop.max);
        return Mathf.Min(Mathf.FloorToInt(ratio * numLevels), numLevels - 1);
    }

    /// <summary>
    /// Devolve o nível de restauração da vila (0–4) com base em regras de design
    /// explícitas (em vez de divisão igual de current/max).
    ///
    ///   Nível 0 — Vila Vazia:   nenhum NPC resgatado.
    ///   Nível 1 — Primeiros:    pelo menos "firstRescueThreshold" NPCs resgatados (padrão 2).
    ///   Nível 2 — Vila Viva:    ≥ 50% resgatados E pelo menos 1 NPC adicional presente
    ///                            (ex: lojista que chegou por missão).
    ///   Nível 3 — Restaurada:   todos os NPCs obrigatórios resgatados (rescuedCount == max).
    ///   Nível 4 — Pós-Boss:     nível 3 + boss do mundo derrotado ("bossDefeated" = true).
    ///
    /// Parâmetros opcionais permitem ajustar os limiares por vila sem alterar este
    /// método (configurados em <see cref="VillageEvolutionController"/>).
    /// </summary>
    public int GetVillageRestorationLevel(string villageId, bool bossDefeated = false, int firstRescueThreshold = 2)
    {
        var pop = GetVillagePopulation(villageId);
        if (pop == null || pop.rescuedCount == 0) return 0;

        bool allRescued = pop.max > 0 && pop.rescuedCount >= pop.max;
        bool halfRescued = pop.max > 0 && (float)pop.rescuedCount / pop.max >= 0.5f;
        bool hasShopNpc  = pop.additionalPopulation > 0;

        if (allRescued && bossDefeated) return 4;
        if (allRescued)                 return 3;
        if (halfRescued && hasShopNpc)  return 2;
        if (pop.rescuedCount >= firstRescueThreshold) return 1;
        return 0;
    }

    // ---------------- Save / Load ----------------

    /// <summary>Copia o estado actual para "data" (usado por SaveManager ao gravar).</summary>
    public void CaptureTo(SaveData data)
    {
        data.timeOfDay = timeOfDay;
        data.weather = weather;

        data.manualTimeActive = manualTimeActive;
        data.manualTimeSaved = manualTimeSaved;

        data.manualWeatherActive = manualWeatherActive;
        data.manualWeatherSaved = manualWeatherSaved;

        data.currentWorldId = currentWorld != null ? currentWorld.worldId : null;
        data.currentAreaId = currentArea != null ? currentArea.areaId : null;

        data.villagePopulations = new List<VillagePopulation>();
        foreach (var pop in villagePopulations)
            data.villagePopulations.Add(new VillagePopulation
            {
                villageId = pop.villageId,
                current = pop.current,
                max = pop.max,
                rescuedCount = pop.rescuedCount,
                additionalPopulation = pop.additionalPopulation
            });
    }

    /// <summary>
    /// Restaura o estado a partir de "data" (usado por SaveManager ao carregar).
    /// currentWorldId/currentAreaId são resolvidos via GameDatabase — se este
    /// não existir ou o ID não for encontrado, currentWorld/currentArea ficam null.
    /// </summary>
    public void RestoreFrom(SaveData data)
    {
        if (data == null) return;

        timeOfDay = data.timeOfDay;
        weather = data.weather;

        manualTimeActive = data.manualTimeActive;
        manualTimeSaved = data.manualTimeSaved;

        manualWeatherActive = data.manualWeatherActive;
        manualWeatherSaved = data.manualWeatherSaved;

        var db = GameDatabase.Instance;
        currentWorld = db != null ? db.FindWorld(data.currentWorldId) : null;
        currentArea = db != null ? db.FindArea(data.currentAreaId) : null;

        villagePopulations.Clear();
        if (data.villagePopulations != null)
            foreach (var pop in data.villagePopulations)
                villagePopulations.Add(new VillagePopulation
                {
                    villageId = pop.villageId,
                    current = pop.current,
                    max = pop.max,
                    rescuedCount = pop.rescuedCount,
                    // Migração v0→v1: additionalPopulation não existia — começa a zero.
                    additionalPopulation = pop.additionalPopulation
                });

        // Re-deriva a população de cada vila a partir dos resgates guardados em
        // PlayerProgress (corrige saves antigos onde villagePopulations era sempre 0,
        // e garante consistência mesmo que AddNpcRescued seja chamado antes deste restore).
        PlayerProgress.Instance?.SyncAllVillagePopulations();

        // Dispara CurrentAreaChanged mesmo que "currentArea" tenha o mesmo
        // valor de antes (SetCurrentArea só dispara em mudanças reais) — um
        // load (mesmo na mesma cena/área) precisa de actualizar banner de
        // área, HUD e outros sistemas ligados a este evento, que de outra
        // forma continuariam a mostrar o estado anterior ao load.
        if (currentArea != null) CurrentAreaChanged?.Invoke(currentArea);
    }
}

[System.Serializable]
public class VillagePopulation
{
    public string villageId;

    /// <summary>
    /// Total de habitantes visíveis (rescuedCount + additionalPopulation).
    /// Valor de exibição — não modificar directamente; usar
    /// <see cref="WorldState.SetVillagePopulation"/> ou
    /// <see cref="WorldState.AddVillagePopulation"/>.
    /// </summary>
    public int current;

    /// <summary>Total de NPCs obrigatórios a resgatar (fonte: AreaData.totalNpcsToRescue).</summary>
    public int max;

    /// <summary>
    /// Número de NPCs oficialmente resgatados (fonte: PlayerProgress.AreaProgress.rescuedNpcIds).
    /// Derivado via <see cref="PlayerProgress.SyncVillagePopulationForWorld"/> —
    /// não alterar directamente.
    /// </summary>
    public int rescuedCount;

    /// <summary>
    /// NPCs adicionais na vila que NÃO foram "resgatados" (lojistas desbloqueados
    /// por missão, visitantes, NPCs de evento). Incrementado por
    /// <see cref="WorldState.AddVillagePopulation"/> e preservado durante
    /// <see cref="PlayerProgress.SyncAllVillagePopulations"/>.
    /// </summary>
    public int additionalPopulation;
}
